    int rows = matrix.size();
    int cols = matrix[0].size();

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            // If the cell is 1, move to the next cell
            if (matrix[i][j] == 1) {
                continue;
            }
            // If the cell is 0, try to make it 1 and move to the next cell
            else {
                matrix[i][j] = 1;
                return true;
            }
        }
    }
    // If we cannot make a permutation matrix, return false
    return false;
}

