// Python solution
class Solution:
    def canPermuteMatrix(self, matrix: List[List[int]]) -> bool:
        rows, cols = len(matrix), len(matrix[0])
        def backtrack(row: int, col: int) -> bool:
            # If we have covered all cells, return true
            if row == rows:
                return True
            # If we have reached the end of a row, move to the next row
            if col == cols:
                return backtrack(row + 1, 0)
            # If the cell is 1, try to flip it and move to the next cell
            if matrix[row][col] == 1:
                matrix[row][col] = 0
                if backtrack(row, col + 1):
                    return True
                # If we cannot flip the cell to a valid permutation matrix, flip it back and try the next cell
                matrix[row][col] = 1
            # If the cell is 0, try to make it 1 and move to the next cell
            else:
                matrix[row][col] = 1
                if backtrack(row, col + 1):
                    return True
                # If we cannot make a permutation matrix, flip the cell back
                matrix[row][col] = 0
            # If we have tried all possible cells and cannot make a permutation matrix, return false
            return False
        # Start the backtracking from the top-left corner
        return backtrack(0, 0)

